/* [REQ-001] [MISRA-Rule-8.13] lowpass_filter_10hz 模块实现 */
#include <stdbool.h>

/* [REQ-001] [MISRA-Rule-8.9] 静态变量 */
static double s_prev = 0.0;
static bool s_fault = false;

/* [REQ-001] [MISRA-Rule-8.4] 函数声明 */
void lowpass_filter_10hz_init(void);
double lowpass_filter_10hz_apply(double input);

/* [REQ-001] [MISRA-Rule-15.7] 初始化函数 */
void lowpass_filter_10hz_init(void) {
    s_prev = 0.0;
    s_fault = false;
}

/* [REQ-001] [MISRA-Rule-15.7] 处理函数 */
double lowpass_filter_10hz_apply(double input) {
    if (input < 0.0 || input > 20000.0) {
        s_fault = true;
        return 0.0;
    }
    double alpha = 0.1;
    double output = alpha * input + (1.0 - alpha) * s_prev;
    s_prev = output;
    return output;
}

